import { useParams, useNavigate } from "react-router-dom";
import { data } from "./CategoryBooksData";
import "./styles/Books.css";

function CategoryBooks() {
  const { name } = useParams();
  const navigate = useNavigate();

  const books = data[name] || [];

  const isBorrowed = (title) => {
    return localStorage.getItem(title) === "borrowed";
  };

  return (
    <div className="books-page">
      <h1 className="books-title">{name}</h1>

      <div className="books-grid">
        {books.map((b, i) => (
          <div
            key={i}
            className="book-card"
            onClick={() =>
              navigate(
                `/book/${encodeURIComponent(b.title)}/${encodeURIComponent(
                  b.author
                )}/${encodeURIComponent(b.cover)}`
              )
            }
          >
            <img
              src={b.cover}
              alt={b.title}
              onError={(e) =>
                (e.target.src =
                  "https://via.placeholder.com/200x280?text=No+Cover")
              }
            />

            <h3>{b.title}</h3>
            <p>{b.author}</p>

            <span
              className={
                isBorrowed(b.title)
                  ? "card-status not-avail"
                  : "card-status avail"
              }
            >
              {isBorrowed(b.title) ? "Not Available" : "Available"}
            </span>
          </div>
        ))}
      </div>
    </div>
  );
}

export default CategoryBooks;
